var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"하, 하늘에서 새하얀 마물들이 내려오고 있어……!","JPN":"そ、空から白い魔物たちが降りて来ている……！","ENG":"Th-there are white monsters coming down from the sky...!","TWN":"哈、哈！天上有雪白的怪物降臨了……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003050","slots":{"L":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"아니야, 저건 마물이 아니야……!","JPN":"違う、あれは魔物じゃない……！","ENG":"No, those aren't monsters...!","TWN":"不是的，那不是怪物……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003050","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"저건 틀림없이 우리를 구원해주기 위해 하늘에서 내려온 천사라고……!","JPN":"あれはきっと私たちを救うために空から降りてきた天使なんだ……！","ENG":"Those are angels that have come down from heaven to save us...!","TWN":"那一定是為了拯救我們從天而降的天使……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003050","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"오오! 천사님, 부디 우리의 죄를……!","JPN":"おお！　天使よ、どうか我々の罪を……！","ENG":"Oh, angels! Please forgive our sin–","TWN":"喔喔！天使大人，請寬恕我們的罪過……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003050","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"젠장, 이건 말도 안 되잖아!","JPN":"くそっ、こんなのあり得ない！","ENG":"Damn it, this is insane!","TWN":"該死，這算什麼？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"한 눈에 봐도 이 세계에 넘어온 6종 침식체가 다섯은 넘어……!","JPN":"ざっと見ただけでも、この世界に渡ってきた第6種侵食体が5体はいる……！","ENG":"Even at a glance, there are more than five Category 6 C.O.s that crossed over...!","TWN":"一眼就能看出，這個世界出現的6類侵蝕體已經超過五種！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그 뿐만이 아니야… 그 여파로 하위 침식체들까지 무더기로 출몰하고 있어……!","JPN":"それだけじゃない……その影響で下位侵食体までわんさか出てきて……！","ENG":"And it's not just them... low-level C.O.s are also pouring in...!","TWN":"不僅如此……由於這個影響，低級侵蝕體也成群出現了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이대로 가다간 정말로……!","JPN":"このままだと、マジで……！","ENG":"If this keeps up, we're really gonna die...!","TWN":"這樣下去真的！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"실망이네요, 카나리아 스쿼드.","JPN":"がっかりです、カナリア・スクワッド。","ENG":"How disappointing, Canary Squad.","TWN":"真讓人失望啊，金絲雀小隊。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 목격했던 이 세계의 멸망은 아직 시작하지도 않았습니다.","JPN":"私が目撃したこの世界の滅亡は、まだ始まってすらいませんよ。","ENG":"The end of this world I foresaw hasn't even begun.","TWN":"我所目睹的這個世界的毀滅還沒有開始。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세계를 바꿀 수 있는 변수를 자처하더니, 겨우 이정도로 절망하는 건가요?","JPN":"世界を変える変数を自負しておいて、この程度で絶望するのですか？","ENG":"You claimed to be the variables that would change the world, but you're already this hopeless?","TWN":"自稱是能改變世界的變數，結果就因為這種程度的事情而絕望嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"노엘…! 제 목소리가 들려요……?","JPN":"ノエル……！　聞こえますか……？","ENG":"Noelle...! Can you hear me...?","TWN":"洛艾兒！你能聽到我的聲音嗎……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"정신 차려요…! 당장 제가 그리로 갈 테니까……!","JPN":"しっかりしてください……！　私がすぐに行きます……！","ENG":"Snap out of it...! I'll come get you right now...!","TWN":"振作一點！我馬上就過去……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"진정해, 꼬맹이!","JPN":"落ち着け、おこちゃま！","ENG":"Calm down, kid!","TWN":"冷靜點，小鬼！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"지금, 이 대열에서 네가 빠지면 우리 전부 죽는다고……!","JPN":"今、この隊列からあんたが抜けたら、こっちは全員死ぬんだ……！","ENG":"If you leave the formation now, we're all dead...!","TWN":"現在，如果你從這個隊伍中退出，我們全都會死！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이거 놔요, 라이카……!","JPN":"離して、ライカ……！","ENG":"Let go of me, Laika...!","TWN":"放開這個，萊卡！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그새 잊어버렸어요? 우리가 여기까지 온 건, 저 아이를 구하기 위해서였잖아요!","JPN":"忘れたの？　私たちがここに来たのは、あの子を助けるためよ！","ENG":"Did you already forget why we came all this way? We're here to save her!","TWN":"這麼快就忘了嗎？我們來到這裡是為了救那個孩子啊！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그 노엘이 저기 있어요! 조금만 달려가면 손 닿을 거리에 있는데……!","JPN":"そのノエルがあそこにいるのよ！　ちょっと走ると、手の届く距離に……！","ENG":"That's Noelle over there! She's just a hand reach away...!","TWN":"那邊就是洛艾兒！她就在伸手可及的距離……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"나도 알고 있어! 그래서 어쩔 건데?","JPN":"私だって知ってるよ！　でもどうするんだ？","ENG":"I know! But so what?!","TWN":"我也知道！那又怎樣？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"여기서 잠시나마 하늘에 떠 있는 허신을 땅으로 떨어트릴 수 있는 건, 너뿐이잖아!","JPN":"この中で一瞬でも空に浮いている虚神を落とせるのは、あんただけなのに！","ENG":"You're the only one who can bring down the Hollow God floating up there, even for a moment!","TWN":"在這裡能暫時將天空中的虛神拉到地面的，只有你啊！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그럼, 라이카는 노엘을 저대로 내버려두자는 거예요?","JPN":"じゃあ、ライカはノエルをあのままにしていいの？","ENG":"So you're saying we just leave Noelle behind?!","TWN":"那麼，萊卡是說要把洛艾兒就那樣放著不管嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"젠장, 그럴 리가 있겠냐……!","JPN":"くそ、そんなわけあるか……！","ENG":"Damn it, of course not...!","TWN":"可惡，怎麼可能！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어이, 유미나! 무슨 방법이 없는 거야?","JPN":"おい、ミナ！　なんか方法はないのか！","ENG":"Hey, Yoo Mina! You got anything?","TWN":"喂，劉米娜！？有辦法了嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};